const amqp = require('amqplib');
const { exec } = require('child_process');
const mysql = require('mysql2/promise');

const RABBITMQ_URL = 'amqp://localhost';
const QUEUE_NAME = 'task_queue';

async function connectToRabbitMQ() {
  try {
    const connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();
    await channel.assertQueue(QUEUE_NAME, { durable: true });
    console.log('Waiting for messages in %s', QUEUE_NAME);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        try {
          const messageContent = msg.content.toString();
          const message = JSON.parse(messageContent);

          if (typeof message.type !== 'string' || typeof message.payload !== 'object') {
            throw new Error('Invalid message format');
          }

          await processMessage(message);
          channel.ack(msg);
        } catch (error) {
          console.error('Error processing message:', error.message);
          channel.nack(msg, false, false);
        }
      }
    }, { noAck: false });
  } catch (error) {
    console.error('Error connecting to RabbitMQ:', error.message);
  }
}

async function processMessage(message) {
  switch (message.type) {
    case 'database_query':
      await executeDatabaseQuery(message.payload);
      break;
    case 'system_command':
      executeSystemCommand(message.payload);
      break;
    default:
      throw new Error('Unknown message type');
  }
}

async function executeDatabaseQuery(payload) {
  const connection = await mysql.createConnection({
    host: 'localhost',
    user: 'root',
    password: 'password',
    database: 'mydb'
  });

  try {
    const [rows] = await connection.execute(payload.query, payload.params);
    console.log('Query result:', rows);
  } catch (error) {
    console.error('Database query error:', error.message);
  } finally {
    await connection.end();
  }
}

function executeSystemCommand(payload) {
  const command = payload.command;
  if (!/^[a-zA-Z0-9_\- ]+$/.test(command)) {
    throw new Error('Invalid command');
  }

  exec(command, (error, stdout, stderr) => {
    if (error) {
      console.error('Command execution error:', error.message);
      return;
    }
    if (stderr) {
      console.error('Command stderr:', stderr);
      return;
    }
    console.log('Command stdout:', stdout);
  });
}

connectToRabbitMQ();